namespace sv_ce038db3437d44768b5c6afde27098e9.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_ce038db3437d44768b5c6afde27098e9.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between position-relative px-0">
        @for (int i = 0; i < _steps.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")">
                @if (isCompleted)
                {
                    <button class="btn step-circle completed-circle mx-auto" @onclick="() => OnStepClicked.InvokeAsync(step)" aria-label="Go back to @_steps[step-1]">
                        <span>✓</span>
                    </button>
                }
                else
                {
                    <div class="step-circle @(isCurrent ? "current-circle" : "future-circle") mx-auto">
                        <span>@step</span>
                    </div>
                }
                <div class="step-label mt-1 small">@_steps[i]</div>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] _steps = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
}

.current-circle {
    background-color: #0d6efd;
    color: white;
    border: 2px solid #0d6efd;
}

.completed-circle {
    background-color: #198754;
    color: white;
    border: 2px solid #198754;
    padding: 0;
    cursor: pointer;
}

.completed-circle:hover {
    background-color: #157347;
    border-color: #157347;
}

.future-circle {
    background-color: #e9ecef;
    color: #6c757d;
    border: 2px solid #dee2e6;
}

.step-label {
    font-size: 0.75rem;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

@namespace sv_ce038db3437d44768b5c6afde27098e9.Components.Pages.Apply
@using sv_ce038db3437d44768b5c6afde27098e9.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Company" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Title" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <div class="form-check mt-4">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            @if (!Entry.IsCurrent)
            {
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="Entry.EndDate" />
                </div>
            }
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

