@namespace sv_ce038db3437d44768b5c6afde27098e9.Components.Pages.Apply

<h4 class="mb-4">Cover Letter</h4>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<div class="mb-3">
    <label class="form-label">Write your cover letter <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="10" maxlength="2000"
              @bind="CoverLetter" @bind:event="oninput" @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / 2000 characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }

    private string? _errorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _errorMessage = "Please write a cover letter before proceeding.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

