@namespace sv_ce038db3437d44768b5c6afde27098e9.Components.Pages.Apply
@using sv_ce038db3437d44768b5c6afde27098e9.Models

<h4 class="mb-4">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p>Your application has been submitted successfully. Your application ID is <strong>@ApplicationId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }

    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _errorMessage = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch
        {
            _errorMessage = "An error occurred while submitting your application. Please try again.";
        }
    }
}

@page "/apply"
@namespace sv_ce038db3437d44768b5c6afde27098e9.Components.Pages.Apply
@rendermode InteractiveServer
@using sv_ce038db3437d44768b5c6afde27098e9.Models
@inject IApplicationService ApplicationService

<PageTitle>Apply</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 1:
            <PersonalInfoStep Model="_personal"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="_workEntries"
                             OnBack="() => GoToStep(_currentStep - 1)"
                             OnNext="() => CompleteAndAdvance(2)" />
            break;
        case 3:
            <ReferencesStep References="_references"
                            OnBack="() => GoToStep(_currentStep - 1)"
                            OnNext="() => CompleteAndAdvance(3)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnBack="() => GoToStep(_currentStep - 1)"
                             OnNext="() => CompleteAndAdvance(4)" />
            break;
        case 5:
            <ReviewStep Personal="_personal"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="_coverLetter"
                        OnBack="() => GoToStep(_currentStep - 1)"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication"
                        IsSubmitting="_isSubmitting"
                        IsSubmitted="_isSubmitted"
                        ApplicationId="_applicationId" />
            break;
    }
</div>

@code {
    private int _currentStep = 1;
    private HashSet<int> _completedSteps = new();

    // Form state
    private PersonalInfoModel _personal = new();
    private List<WorkEntryModel> _workEntries = new() { new() };
    private List<ReferenceModel> _references = new() { new(), new() };
    private string _coverLetter = "";

    // Submission state
    private bool _isSubmitting;
    private bool _isSubmitted;
    private int? _applicationId;

    private void GoToStep(int step)
    {
        if (step >= 1 && step <= 5 && (_completedSteps.Contains(step) || step == _currentStep))
        {
            _currentStep = step;
        }
    }

    private void CompleteAndAdvance(int step)
    {
        _completedSteps.Add(step);
        _currentStep = step + 1;
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        try
        {
            var application = new JobApplication(
                _personal.ToRecord(),
                new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
                _references.Select(r => r.ToRecord()).ToList(),
                _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _isSubmitted = true;
            _completedSteps.Add(5);
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

